class Playground {
    async run(inputs) {
        let gridData;
        try {
            gridData = JSON.parse(inputs[0]);
        } catch (e) {
            this.log("Invalid input format. Please provide a valid 2D array.");
            return null;
        }

        const rows = gridData.length;
        const cols = gridData[0].length;

        // 1. Initialize Visualizer Slots
        this.grid.init(gridData);
        this.vars.init([["maxSum", -Infinity], ["currentRow", 0], ["currentCol", 0]]);
        await this.await();

        let maxSum = -Infinity;

        // 2. Iterate through all possible top-left corners of an hourglass
        for (let r = 0; r <= rows - 3; r++) {
            for (let c = 0; c <= cols - 3; c++) {
                this.vars.put("currentRow", r);
                this.vars.put("currentCol", c);
                this.log(`Checking hourglass starting at (${r}, ${c})`);

                // Highlight hourglass shape
                const hourglassCoords = [
                    [r, c], [r, c + 1], [r, c + 2],  // Top row
                    [r + 1, c + 1],                 // Middle
                    [r + 2, c], [r + 2, c + 1], [r + 2, c + 2] // Bottom row
                ];

                let currentSum = 0;
                for (const [hr, hc] of hourglassCoords) {
                    this.grid.highlight(hr, hc, "#00e0ff");
                    currentSum += gridData[hr][hc];
                }

                this.vars.put("currentSum", currentSum);
                this.log(`Calculated sum: ${currentSum}`);
                await this.await();

                // Check for new Max
                if (currentSum > maxSum) {
                    maxSum = currentSum;
                    this.vars.put("maxSum", maxSum);
                    this.log(`New maximum sum found: ${maxSum}`);

                    // Keep the best one highlighted in a different color briefly
                    for (const [hr, hc] of hourglassCoords) {
                        this.grid.highlight(hr, hc, "#00f5a0");
                    }
                    await this.await();
                }

                // Clear highlights for next iteration
                for (const [hr, hc] of hourglassCoords) {
                    this.grid.highlight(hr, hc, null);
                }
            }
        }

        this.log(`Final maximum sum: ${maxSum}`);
        return maxSum;
    }
}
